1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] } | { op: "claim" };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	const FIRST_INSURANCE_MULTIPLIER = 1.1;
14	const PROCESSING_FEE = 5;
15	
16	const ceilToWholeG = (amount: number): number =>
17	  Math.ceil(Math.round(amount * 100) / 100);
18	
19	const COMPONENT_BUNDLE_PRICE = 60;
20	const COMPONENT_TYPES = new Set(["rune"]);
21	
22	const countsByType = (items: Item[]): Map<string, number> => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
25	  return counts;
26	};
27	
28	const baseForType = (type: string, count: number): number => {
29	  if (COMPONENT_TYPES.has(type)) {
30	    const bundles = Math.floor(count / 3);
31	    const singles = count % 3;
32	    return bundles * COMPONENT_BUNDLE_PRICE + singles * (BASE_PREMIUM[type] ?? 0);
33	  }
34	  return count * (BASE_PREMIUM[type] ?? 0);
35	};
36	
37	const quote = (items: Item[]): number => {
38	  const counts = countsByType(items);
39	  let base = 0;
40	  for (const [type, count] of counts) base += baseForType(type, count);
41	  return ceilToWholeG(base * FIRST_INSURANCE_MULTIPLIER) + PROCESSING_FEE;
42	};
43	
44	const processStep = (step: Step): unknown =>
45	  step.op === "quote" ? { premium: quote(step.items) } : {};
46	
47	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
48	  results: scenario.steps.map(processStep),
49	});
