const baseForType = (type: string, count: number): number => {
  const unitPrice = BASE_PREMIUM[type] ?? 0;
  if (!COMPONENT_TYPES.has(type)) return count * unitPrice;
  const bundles = Math.floor(count / 3);
  const singles = count % 3;
  return bundles * COMPONENT_BUNDLE_PRICE + singles * unitPrice;
};

const quote = (items: Item[]): number => {
  const base = [...countsByType(items)].reduce(
    (sum, [type, count]) => sum + baseForType(type, count),
    0,
  );
  return ceilToWholeG(base * FIRST_INSURANCE_MULTIPLIER) + PROCESSING_FEE;
};
